head.script:
scwin.chkClear = false;     //휴지통 클릭시 그리드 초기화 방지

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    console.log("scwin.onpageload");
    scwin.strCurDate = $c.date.getServerDateTime();
    scwin.strPreDate = $c.date.addMonth(scwin.strCurDate, -1);

    udc_fromToCalendar.setInitDate(scwin.strPreDate, scwin.strCurDate); //udc달력 형식

    scwin.lobranCd = $c.data.getMemInfo("lobranCd");
    scwin.lobranNm = $c.data.getMemInfo("lobranNm");

    const comboOptions = [
        {
            method: "getLuxeComboData",
            param1: "StandardWorkPathEBC",
            param2: "retrieveStandardWorkPathEachOrdKnd",
            param3: ["1", "1", "1", "1", "1", "1", "1"],
            compID: "acb_odrKndCd"
        }
        , {
            method: "getLuxeComboData",
            param1: "StandardWorkPathEBC",
            param2: "retrieveStandardWorkPathCombo",
            param3: [],
            compID: "acb_stdWrkPathNo"
        }
    ];
    $c.data.setGauceUtil(comboOptions, function () {
        acb_odrKndCd.setNodeSet("data:dlt_gauceUtil_acb_odrKndCd", 'name', 'code');
        acb_stdWrkPathNo.setNodeSet("data:dlt_gauceUtil_acb_stdWrkPathNo", 'name', 'code');
        scwin.f_defaultValue();
    });
};

//-------------------------------------------------------------------------
// UDC 로딩
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    console.log("scwin.onUdcCompleted");
    udc_fromToCalendar.setInitDate(scwin.strPreDate, scwin.strCurDate);
}

//-------------------------------------------------------------------------
// 화면 open시 초기 데이타 setting
//-------------------------------------------------------------------------
scwin.f_defaultValue = function () {
    console.log("scwin.f_defaultValue");
    acb_selpchItemCd.focus();

    if (scwin.chkClear == false) rd_cntrBulkYn.setSelectedIndex(0);

    //요율항목 조회
    dma_commSearch.set("sysCd", "SellpurchaseItemEBC");
    dma_commSearch.set("queryId", "retrieveContractSellpurchaseItemList");
    dma_commSearch.set("param1", "21");
    $c.sbm.execute(sbm_commonPopup);
}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_fieldClear = function () {
    console.log("scwin.f_fieldClear");
    udc_fromToCalendar.setInitDate(scwin.strPreDate, scwin.strCurDate); //udc달력 형식
    $c.gus.cfInitObjects(tbl_search, [ed_regDtFrom, ed_regDtTo, rd_cntrBulkYn]);

    scwin.chkClear = true;
    scwin.f_defaultValue();
    scwin.chkClear = false;
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_retrieve = async function () {
    //조회 필수 조건 check
    let chkVal = await $c.gus.cfValidate([tbl_search]);
    if (!chkVal) return;

    if (!$c.gus.cfIsAfterDate(ed_regDtFrom.getValue(), ed_regDtTo.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ed_regDtFrom.focus();
        return;
    }

    $c.sbm.execute(sbm_retrieve);
}

//-------------------------------------------------------------------------
// 공통 팝업 호출
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.f_openCommonPopUp = function (disGubun, pParamCd, pParamNm, pWinCloseTF, pAllSearchTF) {
    //var pParamCd = codeObj.getValue();
    //var pParamNm = nameObj.getValue();

    switch (disGubun) {
        case 1: // 품목/품명
            udc_commCd.cfCommonPopUp(scwin.callBackCommInfo,
                pParamCd,
                pParamNm,
                pWinCloseTF,
                '3',
                '품목/품명코드,품목/품명',
                '150,180,50',
                null,
                '2,4',
                null,
                null,
                null,
                null,
                null,
                pAllSearchTF,
                '품목/품명,품목／품명코드,품목／품명');
            break;

        case 2: // 거래처
            udc_clntNo.cfCommonPopUp(scwin.callBackClntInfo,
                pParamCd,
                pParamNm,
                pWinCloseTF,
                '9',
                '거래처번호,거래처명,,사업자등록번호,요율연결여부,우편번호,주소,상세주소,거래처담당자,',
                '100,100,0,120,100,0,100,100,100,0',
                '3,10',
                'LOGISCLNT1,S,CTRT',
                '800',
                '600',
                null,
                null,
                null,
                "F",
                '거래처,거래처코드,거래처명');
            break;

        case 3: // 등록점소
            udc_regLobranCd.cfCommonPopUp(scwin.callBackLogisDeptInfo,
                pParamCd,
                pParamNm,
                pWinCloseTF,
                '2',
                '등록점소코드,등록점소명',
                '150,180',
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                "F",
                '등록점소,등록점소코드,등록점소명');
            break;

        case 4: // 권역구간(출발)
            udc_dptDistrictCd.cfCommonPopUp(scwin.callBackDptDistrict,
                pParamCd,
                pParamNm,
                pWinCloseTF,
                '2',
                '출발권역코드,출발권역명',
                '150,180',
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                "F",
                '출발권역,출발권역코드,출발권역명');
            break;

        case 5: // 권역구간(도착) 
            udc_arvDistrictCd.cfCommonPopUp(scwin.callBackArvDistrict,
                pParamCd,
                pParamNm,
                pWinCloseTF,
                '2',
                '도착권역코드,도착권역명',
                '150,180',
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                "F",
                '도착권역,도착권역코드,도착권역명');
            break;

        case 6: // 작업구간(출발)
            udc_dptWrkPlCd.cfCommonPopUp(scwin.callBackDptWrkPl,
                pParamCd,
                pParamNm,
                pWinCloseTF,
                '2',
                '작업장코드,작업장명',
                '150,180',
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                "F",
                '작업장,작업장코드,작업장명');
            break;

        case 7: // 작업구간(도착)
            udc_arvWrkPlCd.cfCommonPopUp(scwin.callBackArvWrkPl,
                pParamCd,
                pParamNm,
                pWinCloseTF,
                '2',
                '작업장코드,작업장명',
                '150,180',
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                "F",
                '작업장,작업장코드,작업장명');
            break;

        default:
            break;
    }
}

