        gr_ctrt.setColumnVisible("bulkUnitNm", false);
        gr_ctrt.setColumnVisible("bulkCrcNm", false);
        gr_ctrt.setColumnVisible("eqKndNm", false);
        gr_ctrt.setColumnVisible("trfAdptNm", false);
